function sha256(ascii) {
  function rightRotate(value, amount) { return (value >>> amount) | (value << (32 - amount)); }
  const mathPow = Math.pow, maxWord = mathPow(2, 32);
  let i, j, result = '';
  const words = [], asciiBitLength = ascii.length * 8;
  let hash = [], k = [], primeCounter = k.length;
  const isComposite = {};
  for (let candidate = 2; primeCounter < 64; candidate++) {
    if (!isComposite[candidate]) {
      for (i = 0; i < 313; i += candidate) isComposite[i] = candidate;
      hash[primeCounter] = (mathPow(candidate, 0.5) * maxWord) | 0;
      k[primeCounter++] = (mathPow(candidate, 1/3) * maxWord) | 0;
    }
  }
  ascii += '\x80';
  while (ascii.length % 64 - 56) ascii += '\x00';
  for (i = 0; i < ascii.length; i++) {
    j = ascii.charCodeAt(i);
    if (j >> 8) return;
    words[i >> 2] |= j << ((3 - i) % 4) * 8;
  }
  words[words.length] = (asciiBitLength / maxWord) | 0;
  words[words.length] = asciiBitLength;
  for (j = 0; j < words.length; ) {
    const w = words.slice(j, j += 16), oldHash = hash.slice(0);
    for (i = 0; i < 64; i++) {
      const w15 = w[i - 15], w2 = w[i - 2];
      const a = hash[0], e = hash[4];
      const temp1 = hash[7]
        + (rightRotate(e, 6) ^ rightRotate(e, 11) ^ rightRotate(e, 25))
        + ((e & hash[5]) ^ (~e & hash[6])) + k[i]
        + (w[i] = (i < 16) ? w[i] : (w[i-16]
          + (rightRotate(w15,7) ^ rightRotate(w15,18) ^ (w15 >>> 3))
          + w[i-7] + (rightRotate(w2,17) ^ rightRotate(w2,19) ^ (w2 >>> 10))) | 0);
      const temp2 = (rightRotate(a,2) ^ rightRotate(a,13) ^ rightRotate(a,22))
        + ((a & hash[1]) ^ (a & hash[2]) ^ (hash[1] & hash[2]));
      hash = [(temp1 + temp2) | 0].concat(hash);
      hash[4] = (hash[4] + temp1) | 0;
      hash.length = 8;
    }
    hash = hash.map((x, i) => (x + oldHash[i]) | 0);
  }
  for (i = 0; i < 8; i++)
    for (j = 3; j + 1; j--) { const b = (hash[i] >> (j * 8)) & 255; result += (b < 16 ? '0' : '') + b.toString(16); }
  return result;
}

// Walidacja fbc - odrzuca wartosci starsze niz 90 dni (format: fb.1.{timestamp_ms}.{fbclid})
function isValidFbc(fbc) {
  if (!fbc || typeof fbc !== 'string') return false;
  const parts = fbc.split('.');
  if (parts.length < 4) return false;
  const ts = parseInt(parts[2], 10);
  if (!ts || isNaN(ts)) return false;
  const ninetyDaysMs = 90 * 24 * 60 * 60 * 1000;
  return (Date.now() - ts) < ninetyDaysMs;
}

let body = $input.first().json.body || $input.first().json;
if (typeof body === "string") {
  try { body = JSON.parse(body); } catch(e) { body = {}; }
}
const headers = $input.first().json.headers || {};

// Zmiana 1: event_id bez fallbacku - bez niego brak szansy na deduplikacje z Pixelem
const eventId = body.event_id;
if (!eventId) return [];

const pageUrl   = body.page_url   || 'https://maltaview.pl';
const userAgent = body.user_agent || headers['user-agent'] || '';
const clientIp  = headers['x-real-ip'] || headers['x-forwarded-for'] || body.client_ip || '';

// Zmiana 2: fbp tylko prawdziwy z cookie _fbp, bez fallsyfikatu
const fbp = body.fbp || '';

// fbc: uzyj tylko gdy swiezy (< 90 dni), inaczej pomin
const fbc = isValidFbc(body.fbc) ? body.fbc : '';

// Zmiana 3: USUNIETY external_id (hash z IP+UA dawal ten sam ID dla wielu userow przy Docker internal IP)

const userData = {
  fbp: fbp || undefined,
  fbc: fbc || undefined,
  client_user_agent: userAgent || undefined,
  client_ip_address: clientIp || undefined,
  // Zmiana 5: country dla Polski - darmowy +EMQ, 99% ruchu z PL
  country: [sha256('pl')]
};

Object.keys(userData).forEach(k => { if (userData[k] === undefined) delete userData[k]; });

const capiData = {
  data: [{
    event_name: 'PageView',
    event_time: Math.floor(Date.now() / 1000),
    event_id: eventId,
    action_source: 'website',
    event_source_url: pageUrl,
    user_data: userData
  }]
};

return [{ json: { capiData, eventId, pageUrl } }];

